head.b:skin:
:root{
  /* ── Brand Color Palette (Deep Green & Gold) ── */
  --sm-bg:#050f07;
  --sm-bg2:#0b1a0e;
  --sm-card:rgba(26,92,42,.14);
  --sm-line:rgba(200,169,110,.18);
  --sm-line2:rgba(200,169,110,.30);
  --sm-text:#f0faf3;
  --sm-muted:#8ab89a;
  --sm-muted2:#b0ccb8;

  --sm-primary:#1a5c2a;    /* Deep Forest Green */
  --sm-accent:#2d7a3a;     /* Mid Green */
  --sm-cyan:#4caf73;       /* Light Emerald */
  --sm-gold:#c8a96e;       /* Brand Gold */
  --sm-lime:#e8c98a;       /* Accent Light Gold */
  --sm-pink:var(--sm-primary);

  --sm-radius:30px;
  --sm-shadow:0 30px 90px rgba(0,0,0,.45);
  --sm-shadow-green:0 20px 60px rgba(26,92,42,.35);

  /* Gradients */
  --grad-brand:linear-gradient(135deg,#1a5c2a,#2d7a3a 45%,#c8a96e);
  --grad-gold:linear-gradient(135deg,#c8a96e,#e8c98a 60%,#f0d9a8);
}

*{box-sizing:border-box}
body{
  margin:0;
  font-family:Inter,ui-sans-serif,system-ui,-apple-system,Segoe UI,Arial,sans-serif;
  background:
    radial-gradient(circle at 10% -10%,rgba(26,92,42,.45),transparent 34rem),
    radial-gradient(circle at 80% 0%,rgba(200,169,110,.18),transparent 34rem),
    linear-gradient(135deg,#050f07,#0b1a0e 55%,#13051d);
  color:var(--sm-text);
  overflow-x:hidden;
}
body:before{
  content:"";
  position:fixed;
  inset:0;
  background-image:
    linear-gradient(rgba(200,169,110,.028) 1px,transparent 1px),
    linear-gradient(90deg,rgba(200,169,110,.028) 1px,transparent 1px);
  background-size:34px 34px;
  pointer-events:none;
  mask-image:radial-gradient(circle at 50% 0,#000,transparent 75%);
}
a{color:inherit;text-decoration:none}
.sm-top{
  position:sticky;
  top:0;
  z-index:99;
  background:rgba(5,15,7,.82);
  backdrop-filter:blur(20px);
  border-bottom:1px solid var(--sm-line);
}
.sm-wrap{width:min(1240px,calc(100% - 28px));margin:auto}
.sm-nav{min-height:76px;display:flex;align-items:center;justify-content:space-between;gap:18px}
.sm-brand{display:flex;align-items:center;gap:12px;text-decoration:none}
.sm-mark{
  width:52px;
  height:52px;
  border-radius:18px;
  display:grid;
  place-items:center;
  font-weight:1000;
  letter-spacing:-.08em;
  color:#fff;
  background:var(--grad-brand);
  box-shadow:var(--sm-shadow-green);
}
.sm-mark img{width:100%;height:100%;object-fit:contain;padding:4px}
.sm-brand strong{font-size:1.15rem;color:var(--sm-gold)}
.sm-menu{display:flex;gap:8px;flex-wrap:wrap;align-items:center}
.sm-menu a,.sm-btn,.sm-buy,.sm-cart,.chatbot-open{
  border:1px solid var(--sm-line);
  background:rgba(26,92,42,.14);
  padding:11px 15px;
  border-radius:999px;
  text-decoration:none;
  font-weight:900;
  transition:.2s;
  cursor:pointer;
  color:var(--sm-text);
}
.sm-menu a:hover,.sm-btn:hover,.sm-buy:hover,.sm-cart:hover,.chatbot-open:hover{
  transform:translateY(-2px);
  background:rgba(26,92,42,.28);
  border-color:var(--sm-gold);
}
.sm-buy{
  border:0;
  background:var(--grad-brand);
  color:#07111f;
  display:inline-block;
}
.sm-cart{display:inline-block}
.sm-hero{padding:64px 0 30px}
.sm-hero-card{
  position:relative;
  overflow:hidden;
  border-radius:36px;
  padding:clamp(26px,6vw,68px);
  border:1px solid var(--sm-line);
  background:linear-gradient(145deg,rgba(26,92,42,.22),rgba(200,169,110,.14));
  box-shadow:var(--sm-shadow);
}
.sm-hero-card:after{
  content:"";
  position:absolute;
  right:-80px;
  bottom:-100px;
  width:310px;
  height:310px;
  border-radius:50%;
  background:radial-gradient(circle,var(--sm-cyan),transparent 68%);
  opacity:.38;
  animation:smFloat 6s ease-in-out infinite;
}
.sm-kicker{
  display:inline-flex;
  padding:9px 13px;
  border-radius:999px;
  background:rgba(26,92,42,.2);
  border:1px solid var(--sm-line);
  font-size:.78rem;
  letter-spacing:.1em;
  text-transform:uppercase;
  font-weight:1000;
  color:var(--sm-gold);
}
.sm-hero h1{font-size:clamp(2.5rem,6vw,6.4rem);line-height:.88;letter-spacing:-.075em;margin:16px 0}
.sm-hero p{color:var(--sm-muted2);font-size:clamp(1rem,1.6vw,1.22rem);line-height:1.7;max-width:840px}
.sm-search{display:flex;gap:10px;flex-wrap:wrap;margin-top:24px}
.sm-search input{
  flex:1;
  min-width:250px;
  border:1px solid var(--sm-line);
  background:rgba(26,92,42,.12);
  border-radius:999px;
  color:var(--sm-text);
  padding:15px 18px;
  outline:none;
}
.sm-search button{border:0}
.content-outer,.content-fauxcolumn-outer,.region-inner{max-width:none!important}
.main-outer{width:min(1240px,calc(100% - 28px));margin:auto}
.blog-posts{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:18px;margin:20px 0 60px}
.post-outer,.post{
  background:rgba(26,92,42,.1)!important;
  border:1px solid var(--sm-line);
  border-radius:26px;
  box-shadow:0 20px 70px rgba(0,0,0,.22);
  overflow:hidden;
  transition:.22s;
  padding:0!important;
}
.post-outer:hover,.post:hover{transform:translateY(-4px);border-color:rgba(200,169,110,.56)}
.post-title,.entry-title{font-size:1.05rem!important;line-height:1.25!important;padding:16px 16px 0!important;margin:0!important;color:var(--sm-gold2)}
.post-body,.entry-content{padding:14px 16px 18px!important;color:var(--sm-muted2)!important}
.post-body img{max-width:100%;height:auto;border-radius:18px}
.sm-product-post{display:block}
.sm-pdp-hero{display:grid;grid-template-columns:1.05fr .95fr;gap:20px;margin:18px 0}
.sm-gallery,.sm-buybox,.sm-copy,.sm-page{
  border:1px solid var(--sm-line);
  background:rgba(26,92,42,.14);
  border-radius:28px;
  padding:18px;
  box-shadow:var(--sm-shadow);
}
.sm-main-img{width:100%;max-height:650px;object-fit:cover;border-radius:22px;background:rgba(26,92,42,.08)}
.sm-thumbs{display:grid;grid-template-columns:repeat(5,1fr);gap:9px;margin-top:9px}
.sm-thumbs img{height:95px;width:100%;object-fit:cover;border-radius:14px}
.sm-videos video{width:100%;border-radius:16px;margin-top:10px}
.sm-breadcrumb{font-size:.8rem;color:var(--sm-gold);font-weight:900}
.sm-buybox h1{font-size:clamp(1.8rem,4vw,3.4rem);line-height:1;letter-spacing:-.05em;margin:.2rem 0 1rem}
.sm-price-row{display:flex;gap:12px;align-items:center;flex-wrap:wrap;margin:18px 0}
.sm-price-row strong{font-size:2rem;color:var(--sm-gold2)}
.sm-price-row del{color:var(--sm-muted)}
.sm-price-row span{
  padding:8px 10px;
  border-radius:999px;
  background:var(--grad-gold);
  color:#07111f;
  font-weight:1000;
}
.sm-stock{
  padding:12px 14px;
  border-radius:18px;
  background:rgba(76,175,115,.12);
  border:1px solid rgba(76,175,115,.30);
  font-weight:900;
}
.sm-stock.out{background:rgba(200,169,110,.12);border-color:rgba(200,169,110,.32)}
.sm-ctas{display:flex;gap:10px;flex-wrap:wrap;margin:18px 0}
.sm-tags{display:flex;gap:8px;flex-wrap:wrap;margin:14px 0}
.sm-chip{
  display:inline-flex;
  border:1px solid var(--sm-line);
  background:rgba(26,92,42,.12);
  padding:8px 10px;
  border-radius:999px;
  text-decoration:none;
  font-size:.82rem;
  font-weight:900;
  color:var(--sm-gold2);
}
.sm-trust{color:var(--sm-muted2)}
.sm-copy{margin:20px 0;line-height:1.75}
.sm-category-list{columns:2}
.Label,.BlogArchive,.PopularPosts{background:rgba(26,92,42,.12);border:1px solid var(--sm-line);border-radius:24px;padding:16px;margin:16px 0}

/* ── Chatbot Overlay Styles ── */
.chatbot{
  position:fixed;right:18px;bottom:18px;z-index:90;
  width:min(430px,calc(100vw - 28px));height:min(640px,calc(100vh - 110px));
  display:none;grid-template-rows:auto 1fr auto auto;
  border:1px solid var(--sm-line2);border-radius:30px;
  background:rgba(11,26,14,.97);
  box-shadow:var(--sm-shadow);overflow:hidden;backdrop-filter:blur(24px);
}
.chatbot.open{display:grid;animation:pop .2s ease}
.chat-head{
  display:flex;justify-content:space-between;align-items:center;gap:12px;
  padding:15px;border-bottom:1px solid var(--sm-line);
  background:linear-gradient(135deg,rgba(26,92,42,.3),rgba(200,169,110,.1));
}
.chat-head strong{color:var(--sm-gold)}
.chat-head small{display:block;color:var(--sm-muted);font-weight:800}
.chat-head button{border:1px solid var(--sm-line);background:rgba(26,92,42,.2);color:#fff;border-radius:50%;width:34px;height:34px;cursor:pointer}
.chat-log{padding:14px;overflow:auto;display:grid;gap:10px;align-content:start}
.chat-msg{padding:12px;border-radius:18px;background:rgba(26,92,42,.18);line-height:1.5;color:var(--sm-text)}
.chat-msg.user{background:rgba(200,169,110,.16);justify-self:end;max-width:86%}
.chat-chips{
  display: flex;
  gap: 8px;
  padding: 8px 12px;
  overflow-x: auto;
  scrollbar-width: none;
  border-top: 1px solid var(--sm-line);
  background: rgba(26,92,42,.06);
}
.chat-chips::-webkit-scrollbar { display: none; }
.chat-chip {
  flex: 0 0 auto;
  border: 1px solid var(--sm-line);
  background: rgba(26,92,42,.2);
  color: var(--sm-gold);
  border-radius: 999px;
  padding: 6px 12px;
  font-size: 0.78rem;
  font-weight: 800;
  transition: .18s;
  cursor: pointer;
}
.chat-chip:hover {
  background: rgba(200,169,110,.2);
  border-color: var(--sm-gold);
}
.chat-form{display:flex;gap:8px;padding:12px;border-top:1px solid var(--sm-line)}
.chat-form input{
  flex:1;min-width:0;border:1px solid var(--sm-line);border-radius:16px;
  background:rgba(26,92,42,.14);color:#fff;outline:0;padding:12px;
}
.chat-form button{
  border:0;border-radius:16px;
  background:var(--grad-brand);
  color:#fff;font-weight:1000;padding:0 18px;cursor:pointer;
}

@keyframes smFloat{50%{transform:translate(-30px,-18px) scale(1.06)}}
@keyframes pop{from{opacity:0;transform:translateY(10px) scale(.98)}to{opacity:1;transform:none}}
@media(max-width:980px){.blog-posts{grid-template-columns:repeat(2,1fr)}.sm-pdp-hero{grid-template-columns:1fr}.sm-menu{display:none}}
@media(max-width:640px){.blog-posts{grid-template-columns:1fr}.sm-hero h1{font-size:3rem}.sm-thumbs{grid-template-columns:repeat(3,1fr)}.sm-category-list{columns:1}}
